{"code":"const prs = github.list_pull_requests({ state: "open" });
const total = prs.length;
const byRepo = prs.reduce((m, p) => m.set(p.repo, (m.get(p.repo) || 0) + 1), new Map());
const sorted = [...byRepo.entries()].sort((a, b) => b[1] - a[1]);
const top = sorted[0];
({ total, topRepo: top[0], topCount: top[1], all: Object.fromEntries(sorted) });
"}
